-- 발자국 남기기 미션 54개 (추억 남기기 18 + 음성 녹음 18 + 마음 전하기 18)
-- 이미 같은 id가 있으면 새 내용으로 덮어써서, 항상 보낸 54개 데이터만 남김

ON DUPLICATE KEY UPDATE category=VALUES(category), name=VALUES(name), description=VALUES(description), action_guide=VALUES(action_guide), illustration_prompt=VALUES(illustration_prompt), order_index=VALUES(order_index);
